def check():
    for q, paras in FAQ:
        text = " ".join(paras)
        print(f"{len(text):4d} chars | {q[:55]}")
        assert 480 <= len(text) <= 920, f"OUT OF RANGE ({len(text)}): {q}"
    print("\nall", len(FAQ), "answers within 480-920 chars")


if __name__ == "__main__":
    check()
